class Solution:
    def solve(self, nums: list[int], target: int) -> list[int]:
        # find first occurrence
        lo, hi = 0, len(nums) - 1
        first = -1
        while lo <= hi:
            mid = (lo + hi) // 2
            if nums[mid] < target:
                lo = mid + 1
            else:
                hi = mid - 1
            if nums[mid] == target:
                first = mid
        # find last occurrence
        lo, hi = 0, len(nums) - 1
        last = -1
        while lo <= hi:
            mid = (lo + hi) // 2
            if nums[mid] > target:
                hi = mid - 1
            else:
                lo = mid + 1
            if nums[mid] == target:
                last = mid
        return [first, last]

