#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<int> solve(vector<int>& nums, int target) {
        int n = nums.size();
        int first = -1, last = -1;
        // first occurrence
        int lo = 0, hi = n - 1;
        while (lo <= hi) {
            int mid = lo + (hi - lo) / 2;
            if (nums[mid] < target) {
                lo = mid + 1;
            } else {
                hi = mid - 1;
            }
            if (mid < n && nums[mid] == target) first = mid;
        }
        // last occurrence
        lo = 0; hi = n - 1;
        while (lo <= hi) {
            int mid = lo + (hi - lo) / 2;
            if (nums[mid] > target) {
                hi = mid - 1;
            } else {
                lo = mid + 1;
            }
            if (mid < n && nums[mid] == target) last = mid;
        }
        return {first, last};
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; ++i) cin >> nums[i];
    int target;
    cin >> target;
    Solution sol;
    vector<int> ans = sol.solve(nums, target);
    cout << ans[0] << " " << ans[1] << "\n";
    return 0;
}
